  '  paths:            { ca?, leaf? },           // optional — file path overrides',
  '  caKeySealedMode:  "auto" | "required" | "disabled",  // default: "auto"',
  '  generation:       number,                   // default: 1 — bump to rotate to a new CA',
  '  engine:           engineInstance,           // optional — defaults to b.mtlsEngine',
